+
+fn read_env_csv(name: &str) -> Option<Vec<String>> {
+    std::env::var(name).ok().map(|raw| {
+        raw.split(',')
+            .map(str::trim)
+            .filter(|entry| !entry.is_empty())
+            .map(ToOwned::to_owned)
+            .collect()
+    })
+}
