+fn main() -> HostResult<()> {
+    init_tracing();
+    match fcp_async_core::runtime::block_on_sync(async_main()) {
+        Ok(result) => result,
+        Err(err) => Err(HostError::Internal(format!(
+            "runtime bootstrap failed: {err}"
+        ))),
+    }
+}
