+                event = "doctor_response",
+                overall_status = ?report.overall_status,
+                duration_ms = started_at.elapsed().as_millis() as u64,
+                "doctor request complete"
+            );
+            Ok(Json(report))
+        }
+        Err(err) => {
+            tracing::warn!(
+                event = "doctor_error",
+                error = %err,
+                duration_ms = started_at.elapsed().as_millis() as u64,
+                "doctor request failed"
+            );
+            Err(map_host_error(err))
+        }
+    }
