+    let report = state.budget.report(zone_filter.as_ref()).await;
+    tracing::debug!(
+        event = "budget_report_response",
+        zone_count = report.zones.len(),
+        duration_ms = started_at.elapsed().as_millis() as u64,
+        "budget report request complete"
